+            authenticated = true;
+
+            await auditLogger.logAuthEvent({
+              type: 'jwt_auth_success',
+              userId: verification.payload.userId,
+              ip: req.ip,
+              userAgent: req.headers['user-agent'],
+              timestamp: new Date(),
+            });
+          } else {
+            await auditLogger.logAuthEvent({
+              type: 'jwt_auth_failed',
+              ip: req.ip,
+              userAgent: req.headers['user-agent'],
+              reason: verification.error || 'Invalid token',
+              timestamp: new Date(),
