+  next();
+}
+
+/**
+ * Remove sensitive headers
+ */
+export function removeSensitiveHeaders(
+  req: Request,
+  res: Response,
+  next: NextFunction
+): void {
+  // Remove headers that might leak server information
+  res.removeHeader('X-Powered-By');
+  res.removeHeader('Server');
