+  const middlewares: Array<(req: Request, res: Response, next: NextFunction) => void> = [];
+
+  // Remove sensitive headers
+  middlewares.push(removeSensitiveHeaders);
+
+  // Apply Helmet security headers
+  if (csp) {
+    middlewares.push(securityHeaders);
