+    let index = 0;
+
+    const runNext = (): void => {
+      if (index >= middlewares.length) {
+        next();
+        return;
+      }
+
+      const middleware = middlewares[index++];
+      middleware(req, res, runNext);
+    };
+
+    runNext();
+  };
