+      );
+
+      fileStats.sort((a, b) => b.stats.mtimeMs - a.stats.mtimeMs);
+
+      // Delete files beyond maxFiles limit
+      const filesToDelete = fileStats.slice(this.config.maxFiles);
+      await Promise.all(
+        filesToDelete.map(f => fs.unlink(f.path).catch(err =>
